// Validate input and prepare SSH parameters
const input = $input.first().json;

const host = input.host || '';
const username = input.username || 'root';
const password = input.password || '';
const command = input.command || '';
const timeout = input.timeout || 300;

// Generate unique session ID
const session_id = `ssh_${Date.now()}_${Math.random().toString(36).substr(2, 8)}`;

if (!host) throw new Error('SSH host is required');
if (!command) throw new Error('SSH command is required');

// Validate host format (basic IP/hostname check)
const hostRegex = /^[a-zA-Z0-9._-]+$/;
if (!hostRegex.test(host)) throw new Error(`Invalid host format: ${host}`);

return [{
  json: {
    host,
    username,
    password,
    command,
    timeout,
    session_id,
    start_time: Date.now()
  }
}];

// SSH via child_process (key-based auth, dynamischer Host)
const { execSync } = require('child_process');
const input = $input.first().json;
const { host, username = 'root', command, timeout = 30, session_id, start_time } = input;

let stdout = '', stderr = '', exit_code = 'success', error = null;

try {
    const sshOpts = [
        '-o StrictHostKeyChecking=no',
        '-o UserKnownHostsFile=/dev/null',
        '-o ConnectTimeout=10',
        '-o BatchMode=yes',
        '-o LogLevel=ERROR'
    ].join(' ');

    stdout = execSync(
        `ssh ${sshOpts} ${username}@${host} ${JSON.stringify(command)}`,
        { timeout: timeout * 1000, encoding: 'utf8', shell: '/bin/bash' }
    ).trim();

} catch (e) {
    exit_code = 'failed';
    error = e.message;
    stderr = (e.stderr || '').toString().trim() || e.message;
    stdout = (e.stdout || '').toString().trim();
}

return [{
    json: {
        exit_code,
        stdout,
        stderr,
        execution_time_seconds: Math.round((Date.now() - start_time) / 1000),
        session_id: session_id || `ssh_${Date.now()}`,
        error,
        host,
        command
    }
}];

// Normalize SSH output into standardized result object
const sshResult = $input.first().json;
const prepareData = $('🔧 Validate & Prepare').first().json;

const execution_time_seconds = Math.round((Date.now() - prepareData.start_time) / 1000);
const session_id = prepareData.session_id;

// n8n SSH node returns stdout directly or error
let exit_code = 'success';
let stdout = '';
let stderr = '';
let error = null;

if (sshResult.error) {
  exit_code = 'failed';
  stderr = sshResult.error.message || String(sshResult.error);
  error = stderr;
} else if (sshResult.stdout !== undefined) {
  stdout = sshResult.stdout || '';
  stderr = sshResult.stderr || '';
  // Check for non-zero exit in stderr patterns
  if (sshResult.code && sshResult.code !== 0) {
    exit_code = 'failed';
  }
} else {
  // Direct string output from SSH node
  stdout = typeof sshResult === 'string' ? sshResult : JSON.stringify(sshResult);
}

return [{
  json: {
    exit_code,
    stdout: stdout.trim(),
    stderr: stderr.trim(),
    execution_time_seconds,
    session_id,
    error,
    host: prepareData.host,
    command: prepareData.command
  }
}];

const safetyResult = $('🛡️ SUB: Safety Check').first().json;
const validated = $('🔧 Validate & Prepare').first().json;
return [{ json: {
  success: false,
  blocked: true,
  blocked_reason: safetyResult.blocked_reason || 'Safety Check fehlgeschlagen',
  blocked_commands: safetyResult.blocked_commands || [],
  target: validated.target_host || 'unknown',
  output: ''
}}];

